import { addMessageActionCreator } from "../Redux/dialogs-reducer";

import Dialogs from "./Dialogs";

import { connect } from "react-redux";

const DialogsContainer = (props) => {
  let sendMessage = (messageText) => {
    debugger;
    let action = addMessageActionCreator(messageText);
    props.dispatch(action);
  };

  return (
    <Dialogs
      addMessage={sendMessage}
      dialogsData={props.state.dialogsData}
      messagesData={props.state.messagesData}
    />
  );
};

let mapStateToProps = (state) => {
  return {
    dialogsPage: state.dialogsPage.messagesData,
    messagesData: state.dialogsPage.messagesData,
  };
};

let mapDispatchToProps = (store) => {
  return {
    addMessage: store.dispatch(addMessageActionCreator()),
  };
};

const SuperDialogsContainer = connect(
  mapStateToProps,
  mapDispatchToProps
)(Dialogs);

export default SuperDialogsContainer;
